onClick:
{{
  (async () => {
    // 1. Store setzen
    await storeValue('selectedModus', 'Zeit'); 

    // 2. Query ausführen
    try {
      await Bewaesserung_Speichern.run({
        ventilName: appsmith.store.activeVentil,
        programm: appsmith.store.selectedProg,
        modus: 'Zeit',
        stammDaten: Stammdaten.data
      });

      // 3. Daten neu lesen
      await Bewaesserung_Lesen.run();

      // 4. Modal schließen und Erfolgsmeldung
      closeModal('Modal_Programm');
      showAlert("Programm auf 'Zeit' gespeichert.", "success");

    } catch (e) {
      showAlert("Fehler beim Speichern: " + e.message, "error");
    }
  })()
}}
